            Path uploadDirPath = Paths.get(UPLOAD_DIR).toRealPath();
            Path resolvedPath = fullPath.toRealPath();

            if (!resolvedPath.startsWith(uploadDirPath)) {
                throw new IOException("Access denied: file path is outside the upload directory");
            }

            // Check if file exists
            if (!Files.exists(resolvedPath)) {
                throw new IOException("File not found: " + filePath);
            }

            // Check if it's a regular file
            if (!Files.isRegularFile(resolvedPath)) {
                throw new IOException("Path is not a regular file: " + filePath);
            }

            // Read file content with UTF-8 encoding
            String content = Files.readString(resolvedPath, StandardCharsets.UTF_8);

            logger.log(Level.INFO, "Successfully read file: " + filePath);

            return content;

        } catch (IOException e) {
            logger.log(Level.WARNING, "Failed to read file: " + filePath, e);
            throw e;
        }
    }
}
